    """ For a given number n, find the largest number that divides n evenly, smaller than n
    >>> largest_divisor(15)
    5
    """
    result = n
    for divisor in range(int(math.sqrt(n)) + 1, 1, -1):
        if n % divisor == 0:
            result = divisor
    return result

def largest_divisor(n: int) -> int:
    """ For a given number n, find the largest number that divides n evenly, smaller than n
    >>> largest_divisor(15)
    5
    """
    low: int = 2
    high: int = n // 2

    while low <= high:
        mid: int = (low + high) // 2
        if n % mid == 0:
            return mid
        elif n % mid > 0:
            low = mid + 1
        else:
            high = mid - 1

    return 1

